def bucket_by_pivot(nums, pivot):
    low = []
    mid = []
    high = []
    for n in nums:
        if n < pivot:
            low.append(n)
        elif n == pivot:
            mid.append(n)
        else:
            high.append(n)
    return [low, mid, high]

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_partition(self):
        self.assertEqual(bucket_by_pivot([5, 3, 8, 1, 5, 9, 2], 5), [[3, 1, 2], [5, 5], [8, 9]])

    def test_all_equal(self):
        self.assertEqual(bucket_by_pivot([4, 4, 4], 4), [[], [4, 4, 4], []])

    def test_pivot_not_in_list(self):
        self.assertEqual(bucket_by_pivot([1, 3, 5, 7], 4), [[1, 3], [], [5, 7]])

    def test_hidden_empty_list(self):
        self.assertEqual(bucket_by_pivot([], 10), [[], [], []])

    def test_hidden_all_less(self):
        self.assertEqual(bucket_by_pivot([1, 2, 3], 10), [[1, 2, 3], [], []])

    def test_hidden_all_greater(self):
        self.assertEqual(bucket_by_pivot([10, 20, 30], 5), [[], [], [10, 20, 30]])

    def test_hidden_single_element_equal(self):
        self.assertEqual(bucket_by_pivot([7], 7), [[], [7], []])

    def test_hidden_negative_numbers(self):
        self.assertEqual(bucket_by_pivot([-3, -1, 0, 2, -5], 0), [[-3, -1, -5], [0], [2]])

    def test_hidden_single_element_less(self):
        self.assertEqual(bucket_by_pivot([3], 5), [[3], [], []])

    def test_hidden_mixed_order_preserved(self):
        self.assertEqual(bucket_by_pivot([9, 1, 5, 3, 5, 7, 2], 5), [[1, 3, 2], [5, 5], [9, 7]])

if __name__ == '__main__':
    unittest.main()
